131→/// Return the projects directory for the current working directory.
132→/// If inside a git worktree, resolves to the main repo root so sessions
133→/// are found under the original project path.
134→pub fn current_project_dir() -> Result<String, String> {
135→    let cwd = std::env::current_dir().map_err(|e| e.to_string())?;
136→    let cwd_str = cwd.to_string_lossy().to_string();
137→
138→    // Resolve git root for worktree support.
139→    let resolved = super::project::resolve_git_root(&cwd_str);
140→    project_dir_for_path(&resolved)
141→}
