 15→const WATCHER_DEBOUNCE: Duration = Duration::from_millis(200);
 16→
 17→/// Run a debounced file-change loop: receive notify events, apply `filter`,
 18→/// and send a signal after `WATCHER_DEBOUNCE` of quiet time.
 19→fn run_debounce_loop(
 20→    rx: std::sync::mpsc::Receiver<Result<notify::Event, notify::Error>>,
 21→    filter: impl Fn(&notify::Event) -> bool,
 22→    signal_tx: mpsc::Sender<()>,
 23→) {
 24→    let mut debounce_timer: Option<std::time::Instant> = None;
 25→
 26→    loop {
 27→        match rx.recv_timeout(Duration::from_millis(100)) {
 28→            Ok(Ok(event)) => {
 29→                if filter(&event) {
 30→                    debounce_timer = Some(std::time::Instant::now());
 31→                }
 32→            }
 33→            Ok(Err(_)) => {}
 34→            Err(std::sync::mpsc::RecvTimeoutError::Timeout) => {}
 35→            Err(std::sync::mpsc::RecvTimeoutError::Disconnected) => break,
 36→        }
 37→
 38→        if let Some(timer) = debounce_timer {
 39→            if timer.elapsed() >= WATCHER_DEBOUNCE {
 40→                debounce_timer = None;
 41→                let _ = signal_tx.try_send(());
 42→            }
 43→        }
 44→    }
 45→}
