198→/// Serializable picker refresh event.
199→#[derive(Clone, serde::Serialize)]
200→struct PickerRefreshPayload {
201→    sessions: Vec<crate::parser::session::SessionInfo>,
202→}
203→
204→/// Start watching project directories for new/changed sessions.
205→pub fn start_picker_watcher(project_dirs: Vec<String>, app: AppHandle) -> WatcherHandle {
206→    let (stop_tx, mut stop_rx) = mpsc::channel::<()>(1);
207→    let (signal_tx, mut signal_rx) = mpsc::channel::<()>(4);
208→
209→    let dirs_clone = project_dirs.clone();
210→    let signal_tx_clone = signal_tx.clone();
211→
212→    // Spawn the file watcher thread.
213→    std::thread::spawn(move || {
214→        let signal_tx = signal_tx_clone;
215→        let (tx, rx) = std::sync::mpsc::channel();
216→        let mut watcher = match RecommendedWatcher::new(tx, Config::default()) {
217→            Ok(w) => w,
218→            Err(_) => return,
219→        };
220→
221→        for dir in &dirs_clone {
222→            if Path::new(dir).exists() {
223→                let _ = watcher.watch(Path::new(dir), RecursiveMode::Recursive);
224→            }
225→        }
226→
227→        run_debounce_loop(
228→            rx,
229→            |event| {
230→                event.paths.iter().any(|p| {
231→                    let name = p.file_name().and_then(|n| n.to_str()).unwrap_or("");
232→                    name.ends_with(".jsonl")
233→                })
234→            },
235→            signal_tx,
236→        );
237→    });
238→
239→    // Spawn the async refresh loop.
240→    tauri::async_runtime::spawn(async move {
241→        loop {
242→            tokio::select! {
243→                _ = stop_rx.recv() => {
244→                    break;
245→                }
246→                Some(()) = signal_rx.recv() => {
247→                    let sessions = crate::parser::session::discover_all_project_sessions(&project_dirs)
248→                        .unwrap_or_default();
249→
250→                    let payload = PickerRefreshPayload { sessions };
251→                    let _ = app.emit("picker-refresh", payload);
252→                }
253→            }
254→        }
255→    });
256→
257→    WatcherHandle { stop_tx }
258→}
