 12→/// Load a session file and return display messages.
 13→#[tauri::command]
 14→pub async fn load_session(path: String) -> Result<LoadResult, String> {
 15→    if path.is_empty() {
 16→        return Err("no session path provided".to_string());
 17→    }
 18→
 19→    let (classified, _new_offset, _) = read_session_incremental(&path, 0)?;
 20→    let mut chunks = build_chunks(&classified);
 21→
 22→    // Discover and link subagent execution traces.
 23→    let (mut all_procs, color_map) = discover_and_link_all(&path, &chunks);
 24→
 25→    // Inject orphan subagents (no parent tool_use in main session yet).
 26→    inject_orphan_subagents(&mut chunks, &mut all_procs);
 27→
 28→    let ongoing = OngoingChecker::new(&chunks, &all_procs, &path).is_ongoing();
 29→
 30→    let teams = reconstruct_teams(&chunks, &all_procs);
 31→    let messages = chunks_to_messages(&chunks, &all_procs, &color_map);
 32→    let meta = extract_session_meta(&path);
 33→
 34→    // Scan main session + subagent files with global requestId dedup.
 35→    let scanned = crate::parser::session::scan_session_metadata(&path);
 36→    let session_totals = SessionTotals {
 37→        total_tokens: scanned.total_tokens,
 38→        input_tokens: scanned.input_tokens,
 39→        output_tokens: scanned.output_tokens,
 40→        cache_read_tokens: scanned.cache_read_tokens,
 41→        cache_creation_tokens: scanned.cache_creation_tokens,
 42→        cost_usd: scanned.cost_usd,
 43→        model: scanned.model,
 44→    };
 45→
 46→    Ok(LoadResult {
 47→        messages,
 48→        teams,
 49→        path: path.clone(),
 50→        ongoing,
 51→        meta,
 52→        session_totals,
 53→    })
 54→}
