 30→/// Checks if a tool_use block is a SendMessage shutdown_response with approve: true.
 31→pub fn is_shutdown_approval(tool_name: &str, tool_input: &Option<Value>) -> bool {
 32→    if tool_name != "SendMessage" {
 33→        return false;
 34→    }
 35→    let input = match tool_input {
 36→        Some(v) => v,
 37→        None => return false,
 38→    };
 39→    if let Some(obj) = input.as_object() {
 40→        let msg_type = obj.get("type").and_then(|v| v.as_str()).unwrap_or("");
 41→        let approve = obj.get("approve").and_then(|v| v.as_bool());
 42→        if msg_type == "shutdown_response" && approve == Some(true) {
 43→            return true;
 44→        }
 45→    }
 46→    // Fallback to regex.
 47→    APPROVE_PATTERN.is_match(&input.to_string())
 48→}
