175→// ---------------------------------------------------------------------------
176→// OngoingChecker — determines whether a session (or subagent) is ongoing
177→// ---------------------------------------------------------------------------
178→
179→/// Checks ongoing status by combining chunk analysis, subagent state, and file staleness.
180→pub struct OngoingChecker<'a> {
181→    chunks: &'a [Chunk],
182→    procs: &'a [super::subagent::SubagentProcess],
183→    session_path: &'a str,
184→}
185→
186→impl<'a> OngoingChecker<'a> {
187→    pub fn new(
188→        chunks: &'a [Chunk],
189→        procs: &'a [super::subagent::SubagentProcess],
190→        session_path: &'a str,
191→    ) -> Self {
192→        Self {
193→            chunks,
194→            procs,
195→            session_path,
196→        }
197→    }
198→
199→    /// Full ongoing check: chunks → subagents → file staleness.
200→    pub fn is_ongoing(&self) -> bool {
201→        // If the main session chunks are still in progress, gate on the main file freshness.
202→        if self.chunks_ongoing() {
203→            return self.is_file_fresh();
204→        }
205→        // If any subagent is still running, the session is ongoing.
206→        // Subagent staleness is already checked per-file inside is_subagent_ongoing,
207→        // so we don't re-check the main session file here.
208→        self.any_subagent_ongoing()
209→    }
210→
211→    /// Check if a subagent process is ongoing (chunk-based + file staleness).
212→    pub fn is_subagent_ongoing(proc: &super::subagent::SubagentProcess) -> bool {
213→        Self::is_chunks_ongoing(&proc.chunks) && apply_staleness(true, proc.file_mod_time)
214→    }
215→
216→    /// Cascading check: returns true if `proc` or any of its descendant subagents are ongoing.
217→    pub fn is_subagent_ongoing_deep(
218→        proc: &super::subagent::SubagentProcess,
219→        all_procs: &[super::subagent::SubagentProcess],
220→    ) -> bool {
221→        if Self::is_subagent_ongoing(proc) {
222→            return true;
223→        }
224→        // Collect tool_ids from this proc's chunks to find child processes.
225→        let child_tool_ids: HashSet<&str> = proc
226→            .chunks
227→            .iter()
228→            .flat_map(|c| c.items.iter())
229→            .filter(|it| {
230→                it.item_type == DisplayItemType::Subagent
231→                    || ((it.tool_name == "Task" || it.tool_name == "Agent")
232→                        && it.item_type == DisplayItemType::ToolCall)
233→            })
234→            .map(|it| it.tool_id.as_str())
235→            .collect();
236→        if child_tool_ids.is_empty() {
237→            return false;
238→        }
239→        all_procs
240→            .iter()
241→            .filter(|p| child_tool_ids.contains(p.parent_task_id.as_str()))
242→            .any(|p| Self::is_subagent_ongoing_deep(p, all_procs))
243→    }
244→
245→    /// Reports whether the chunks indicate the session is still in progress.
246→    pub fn is_chunks_ongoing(chunks: &[Chunk]) -> bool {
247→        if chunks.is_empty() {
248→            return false;
249→        }
250→
251→        // Trailing user prompt means Claude is processing.
252→        if chunks.last().map(|c| &c.chunk_type) == Some(&ChunkType::User) {
253→            return true;
254→        }
255→
256→        let activity_log = ActivityLog::from_chunks(chunks);
257→
258→        if activity_log.has_items {
259→            if activity_log.is_ongoing() {
260→                return true;
261→            }
262→            return Self::has_pending_agents(chunks);
263→        }
264→
265→        // Fallback for old-style chunks.
266→        for c in chunks.iter().rev() {
267→            if c.chunk_type == ChunkType::AI {
268→                return c.stop_reason != "end_turn";
269→            }
270→        }
271→
272→        false
273→    }
274→
275→    // -- Private helpers --
276→
277→    fn chunks_ongoing(&self) -> bool {
278→        Self::is_chunks_ongoing(self.chunks)
279→    }

 1→use std::collections::HashMap;
 2→use std::sync::Mutex;
 3→use std::time::SystemTime;
 4→
 5→use super::ongoing::apply_staleness;
 6→use super::session::{discover_project_sessions_with_scan, SessionInfo};
 7→
 8→/// Per-file cache entry keyed by (modTime, size).
 9→struct CachedFile {
10→    mod_time: SystemTime,
11→    size: u64,
12→    info: SessionInfo,
13→}
14→
15→/// SessionCache avoids rescanning unchanged session files on every picker
16→/// refresh. The cache key is (path, modTime, size) — when a file's modification
17→/// time or size changes, we rescan it. Files that haven't changed return
18→/// cached metadata immediately.
19→pub struct SessionCache {
20→    file_cache: Mutex<HashMap<String, CachedFile>>,
21→}
22→
23→impl SessionCache {
24→    pub fn new() -> Self {
25→        Self {
26→            file_cache: Mutex::new(HashMap::new()),
27→        }
28→    }
29→
30→    /// Get cached SessionInfo or rescan if file changed.
31→    pub fn get_or_scan(&self, path: &str, mod_time: SystemTime, size: u64) -> Option<SessionInfo> {
32→        let mut cache = self.file_cache.lock().unwrap();
33→        if let Some(cached) = cache.get(path) {
34→            if cached.mod_time == mod_time && cached.size == size {
35→                let mut info = cached.info.clone();
36→                // Re-check staleness for ongoing sessions at read time
37→                info.is_ongoing = apply_staleness(info.is_ongoing, mod_time);
38→                // Also check subagent files (orphan agents may be running
39→                // while the parent session file hasn't changed).
40→                if !info.is_ongoing {
41→                    info.is_ongoing = crate::parser::subagent::has_recently_active_subagents(path);
42→                }
43→                return Some(info);
44→            }
45→        }
46→
47→        // Cache miss or stale — rescan.
48→        let meta = super::session::scan_session_metadata(path);
49→        let info = super::session::session_info_from_metadata(path, mod_time, meta);
50→        cache.insert(
51→            path.to_string(),
52→            CachedFile {
53→                mod_time,
54→                size,
55→                info: info.clone(),
56→            },
57→        );
58→        Some(info)
59→    }
60→
61→    /// Discover sessions across multiple project directories with per-file caching.
62→    pub fn discover_all_project_sessions(
63→        &self,
64→        project_dirs: &[String],
65→    ) -> Result<Vec<SessionInfo>, String> {
66→        let mut all = Vec::new();
67→        for dir in project_dirs {
68→            if let Ok(sessions) =
69→                discover_project_sessions_with_scan(dir, |path, mod_time, size| {
70→                    self.get_or_scan(path, mod_time, size)
71→                })
72→            {
73→                all.extend(sessions);
74→            }
75→        }
76→        all.sort_by(|a, b| b.mod_time.cmp(&a.mod_time));
77→        Ok(all)
78→    }
79→}
