  1→use chrono::{DateTime, Utc};
  2→use lazy_static::lazy_static;
  3→use regex::Regex;
  4→use serde_json::Value;
  5→use std::collections::HashSet;
  6→use std::time::Duration;
  7→
  8→use super::chunk::*;
  9→
 10→/// Maximum time since last file modification before a session is dead.
 11→pub const ONGOING_STALENESS_THRESHOLD: Duration = Duration::from_secs(60);
 12→
 13→/// Returns true if the session is still ongoing (not stale).
 14→/// Returns false if `is_ongoing` is false, or if `mod_time` exceeds the staleness threshold.
 15→pub fn apply_staleness(is_ongoing: bool, mod_time: impl Into<DateTime<Utc>>) -> bool {
 16→    if !is_ongoing {
 17→        return false;
 18→    }
 19→    let elapsed = Utc::now()
 20→        .signed_duration_since(mod_time.into())
 21→        .to_std()
 22→        .unwrap_or(Duration::ZERO);
 23→    elapsed <= ONGOING_STALENESS_THRESHOLD
 24→}
 25→
 26→lazy_static! {
 27→    static ref APPROVE_PATTERN: Regex = Regex::new(r#""approve"\s*:\s*true"#).unwrap();
 28→}
 29→
 30→/// Checks if a tool_use block is a SendMessage shutdown_response with approve: true.
 31→pub fn is_shutdown_approval(tool_name: &str, tool_input: &Option<Value>) -> bool {
 32→    if tool_name != "SendMessage" {
 33→        return false;
 34→    }
 35→    let input = match tool_input {
 36→        Some(v) => v,
 37→        None => return false,
 38→    };
 39→    if let Some(obj) = input.as_object() {
 40→        let msg_type = obj.get("type").and_then(|v| v.as_str()).unwrap_or("");
 41→        let approve = obj.get("approve").and_then(|v| v.as_bool());
 42→        if msg_type == "shutdown_response" && approve == Some(true) {
 43→            return true;
 44→        }
 45→    }
 46→    // Fallback to regex.
 47→    APPROVE_PATTERN.is_match(&input.to_string())
 48→}
 49→
 50→// ---------------------------------------------------------------------------
 51→// ActivityType — classifies each item in a chunk for ongoing analysis
 52→// ---------------------------------------------------------------------------
 53→
 54→#[derive(Debug, Clone, PartialEq)]
 55→enum ActivityType {
 56→    TextOutput,
 57→    Thinking,
 58→    ToolUse,
 59→    ToolResult,
 60→    Interruption,
 61→    ExitPlanMode,
 62→}
 63→
 64→impl ActivityType {
 65→    fn is_ending(&self) -> bool {
 66→        matches!(
 67→            self,
 68→            ActivityType::TextOutput | ActivityType::Interruption | ActivityType::ExitPlanMode
 69→        )
 70→    }
 71→
 72→    fn is_ai_activity(&self) -> bool {
 73→        matches!(
 74→            self,
 75→            ActivityType::Thinking | ActivityType::ToolUse | ActivityType::ToolResult
 76→        )
 77→    }
 78→}
 79→
 80→// ---------------------------------------------------------------------------
 81→// ActivityLog — collects indexed activities from chunks and checks ongoing
 82→// ---------------------------------------------------------------------------
 83→
 84→struct ActivityLog {
 85→    entries: Vec<(ActivityType, usize)>,
 86→    has_items: bool,
 87→}
 88→
 89→impl ActivityLog {
 90→    /// Scan all AI chunks and build an ordered activity log.
 91→    fn from_chunks(chunks: &[Chunk]) -> Self {
 92→        let mut entries: Vec<(ActivityType, usize)> = Vec::new();
 93→        let mut idx = 0;
 94→        let mut has_items = false;
 95→        let mut shutdown_tool_ids: HashSet<String> = HashSet::new();
 96→
 97→        for chunk in chunks {
 98→            if chunk.chunk_type != ChunkType::AI || chunk.items.is_empty() {
 99→                continue;
100→            }
101→            has_items = true;
102→
103→            for item in &chunk.items {
104→                match item.item_type {
105→                    DisplayItemType::Thinking => {
106→                        entries.push((ActivityType::Thinking, idx));
107→                        idx += 1;
108→                    }
109→                    DisplayItemType::Output => {
110→                        if !item.text.trim().is_empty() {
111→                            entries.push((ActivityType::TextOutput, idx));
112→                            idx += 1;
113→                        }
114→                    }
115→                    DisplayItemType::ToolCall => {
116→                        if item.tool_name == "ExitPlanMode" {
117→                            entries.push((ActivityType::ExitPlanMode, idx));
118→                            idx += 1;
119→                        } else if is_shutdown_approval(&item.tool_name, &item.tool_input) {
120→                            shutdown_tool_ids.insert(item.tool_id.clone());
121→                            entries.push((ActivityType::Interruption, idx));
122→                            idx += 1;
123→                        } else {
124→                            entries.push((ActivityType::ToolUse, idx));
125→                            idx += 1;
126→                        }
127→                        if !item.tool_result.is_empty() {
128→                            if shutdown_tool_ids.contains(&item.tool_id) {
129→                                entries.push((ActivityType::Interruption, idx));
130→                            } else {
131→                                entries.push((ActivityType::ToolResult, idx));
132→                            }
133→                            idx += 1;
134→                        }
135→                    }
136→                    DisplayItemType::Subagent => {
137→                        entries.push((ActivityType::ToolUse, idx));
138→                        idx += 1;
139→                        if !item.tool_result.is_empty() {
140→                            entries.push((ActivityType::ToolResult, idx));
141→                            idx += 1;
142→                        }
143→                    }
144→                    DisplayItemType::TeammateMessage | DisplayItemType::HookEvent => {}
145→                }
146→            }
147→        }
148→
149→        Self { entries, has_items }
150→    }
151→
152→    /// True if the last meaningful activity is not an ending (text/interruption).
153→    fn is_ongoing(&self) -> bool {
154→        if self.entries.is_empty() {
155→            return false;
156→        }
157→
158→        let last_ending_idx = self
159→            .entries
160→            .iter()
161→            .rev()
162→            .find(|(at, _)| at.is_ending())
163→            .map(|(_, idx)| *idx);
164→
165→        match last_ending_idx {
166→            None => self.entries.iter().any(|(at, _)| at.is_ai_activity()),
167→            Some(lei) => self
168→                .entries
169→                .iter()
170→                .any(|(at, idx)| *idx > lei && at.is_ai_activity()),
171→        }
172→    }
173→}
174→
175→// ---------------------------------------------------------------------------
176→// OngoingChecker — determines whether a session (or subagent) is ongoing
177→// ---------------------------------------------------------------------------
178→
179→/// Checks ongoing status by combining chunk analysis, subagent state, and file staleness.
180→pub struct OngoingChecker<'a> {
181→    chunks: &'a [Chunk],
182→    procs: &'a [super::subagent::SubagentProcess],
183→    session_path: &'a str,
184→}
185→
186→impl<'a> OngoingChecker<'a> {
187→    pub fn new(
188→        chunks: &'a [Chunk],
189→        procs: &'a [super::subagent::SubagentProcess],
190→        session_path: &'a str,
191→    ) -> Self {
192→        Self {
193→            chunks,
194→            procs,
195→            session_path,
196→        }
197→    }
198→
199→    /// Full ongoing check: chunks → subagents → file staleness.
200→    pub fn is_ongoing(&self) -> bool {
201→        // If the main session chunks are still in progress, gate on the main file freshness.
202→        if self.chunks_ongoing() {
203→            return self.is_file_fresh();
204→        }
205→        // If any subagent is still running, the session is ongoing.
206→        // Subagent staleness is already checked per-file inside is_subagent_ongoing,
207→        // so we don't re-check the main session file here.
208→        self.any_subagent_ongoing()
209→    }
210→
211→    /// Check if a subagent process is ongoing (chunk-based + file staleness).
212→    pub fn is_subagent_ongoing(proc: &super::subagent::SubagentProcess) -> bool {
213→        Self::is_chunks_ongoing(&proc.chunks) && apply_staleness(true, proc.file_mod_time)
214→    }
215→
216→    /// Cascading check: returns true if `proc` or any of its descendant subagents are ongoing.
217→    pub fn is_subagent_ongoing_deep(
218→        proc: &super::subagent::SubagentProcess,
219→        all_procs: &[super::subagent::SubagentProcess],
220→    ) -> bool {
221→        if Self::is_subagent_ongoing(proc) {
222→            return true;
223→        }
224→        // Collect tool_ids from this proc's chunks to find child processes.
225→        let child_tool_ids: HashSet<&str> = proc
226→            .chunks
227→            .iter()
228→            .flat_map(|c| c.items.iter())
229→            .filter(|it| {
230→                it.item_type == DisplayItemType::Subagent
231→                    || ((it.tool_name == "Task" || it.tool_name == "Agent")
232→                        && it.item_type == DisplayItemType::ToolCall)
233→            })
234→            .map(|it| it.tool_id.as_str())
235→            .collect();
236→        if child_tool_ids.is_empty() {
237→            return false;
238→        }
239→        all_procs
240→            .iter()
241→            .filter(|p| child_tool_ids.contains(p.parent_task_id.as_str()))
242→            .any(|p| Self::is_subagent_ongoing_deep(p, all_procs))
243→    }
244→
245→    /// Reports whether the chunks indicate the session is still in progress.
246→    pub fn is_chunks_ongoing(chunks: &[Chunk]) -> bool {
247→        if chunks.is_empty() {
248→            return false;
249→        }
250→
251→        // Trailing user prompt means Claude is processing.
252→        if chunks.last().map(|c| &c.chunk_type) == Some(&ChunkType::User) {
253→            return true;
254→        }
255→
256→        let activity_log = ActivityLog::from_chunks(chunks);
257→
258→        if activity_log.has_items {
259→            if activity_log.is_ongoing() {
260→                return true;
261→            }
262→            return Self::has_pending_agents(chunks);
263→        }
264→
265→        // Fallback for old-style chunks.
266→        for c in chunks.iter().rev() {
267→            if c.chunk_type == ChunkType::AI {
268→                return c.stop_reason != "end_turn";
269→            }
270→        }
271→
272→        false
273→    }
274→
275→    // -- Private helpers --
276→
277→    fn chunks_ongoing(&self) -> bool {
278→        Self::is_chunks_ongoing(self.chunks)
279→    }
280→
281→    fn any_subagent_ongoing(&self) -> bool {
282→        self.procs.iter().any(Self::is_subagent_ongoing)
283→    }
284→
285→    fn is_file_fresh(&self) -> bool {
286→        if let Ok(info) = std::fs::metadata(self.session_path) {
287→            if let Ok(modified) = info.modified() {
288→                return apply_staleness(true, modified);
289→            }
290→        }
291→        true // If we can't read metadata, assume fresh
292→    }
293→
294→    fn has_pending_agents(chunks: &[Chunk]) -> bool {
295→        for chunk in chunks {
296→            if chunk.chunk_type != ChunkType::AI {
297→                continue;
298→            }
299→            for item in &chunk.items {
300→                match item.item_type {
301→                    DisplayItemType::Subagent => {
302→                        if item.tool_result.is_empty() {
303→                            return true;
304→                        }
305→                    }
306→                    DisplayItemType::ToolCall => {
307→                        if (item.tool_name == "Task" || item.tool_name == "Agent")
308→                            && item.tool_result.is_empty()
309→                        {
310→                            return true;
311→                        }
312→                    }
313→                    _ => {}
314→                }
315→            }
316→        }
317→        false
318→    }
319→}
