                    .and_then(|v| v.as_i64())
                    .unwrap_or(0),
                output,
                cache_read: usage
                    .get("cache_read_input_tokens")
                    .and_then(|v| v.as_i64())
                    .unwrap_or(0),
                cache_create: usage
                    .get("cache_creation_input_tokens")
                    .and_then(|v| v.as_i64())
                    .unwrap_or(0),
                model: model_str.to_string(),
                has_stop_reason: has_stop,
            };

