import { useState, useEffect, useCallback, useMemo } from "react";
import { invoke } from "@tauri-apps/api/core";
import type { SessionInfo } from "../types";
import { useTauriEvent } from "./useTauriEvent";

interface PickerState {
  sessions: SessionInfo[];
  loading: boolean;
  searchQuery: string;
}

/** Override ongoing status for a specific session (from the session watcher). */
interface OngoingOverride {
  path: string;
  ongoing: boolean;
}

export function usePicker(
  selectedProject: string | null = null,
  ongoingOverride?: OngoingOverride,
) {
  const [state, setState] = useState<PickerState>({
    sessions: [],
    loading: false,
    searchQuery: "",
  });

  const discoverSessions = useCallback(async (projectDirs: string[]) => {
    setState((prev) => ({ ...prev, loading: true }));
    try {
      const sessions = await invoke<SessionInfo[]>("discover_sessions", {
        projectDirs,
      });
      setState((prev) => ({ ...prev, sessions, loading: false }));

      // Start watching for new sessions
      try {
        await invoke<void>("watch_picker", { projectDirs });
      } catch {
        // watcher is optional
      }
    } catch (err) {
      console.error("Failed to discover sessions:", err);
      setState((prev) => ({ ...prev, loading: false }));
    }
  }, []);

  const setSearchQuery = useCallback((query: string) => {
    setState((prev) => ({ ...prev, searchQuery: query }));
  }, []);

  // Listen for picker-refresh events (backend already applies staleness)
  useTauriEvent<{ sessions: SessionInfo[] }>("picker-refresh", (payload) => {
    setState((prev) => ({
      ...prev,
      sessions: payload.sessions,
    }));
  });

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      invoke<void>("unwatch_picker").catch(() => {});
    };
  }, []);

  // Apply ongoing override from the session watcher — ensures the currently
  // viewed session always shows correct ongoing status without a render delay.
  const allSessions = useMemo(() => {
    if (!ongoingOverride) return state.sessions;
    const { path, ongoing } = ongoingOverride;
    const idx = state.sessions.findIndex((s) => s.path === path);
    if (idx === -1 || state.sessions[idx].is_ongoing === ongoing) return state.sessions;
    const sessions = [...state.sessions];
    sessions[idx] = { ...sessions[idx], is_ongoing: ongoing };
    return sessions;
  }, [state.sessions, ongoingOverride]);

  // Filter sessions by search query
  let filteredSessions = state.searchQuery
    ? allSessions.filter(
        (s) =>
          s.first_message.toLowerCase().includes(state.searchQuery.toLowerCase()) ||
          s.session_id.toLowerCase().includes(state.searchQuery.toLowerCase()) ||
          s.model.toLowerCase().includes(state.searchQuery.toLowerCase()),
      )
    : allSessions;

  // Filter by selected project
  if (selectedProject) {
    filteredSessions = filteredSessions.filter((s) =>
      s.path.replace(/\\/g, "/").includes(`/.claude/projects/${selectedProject}/`),
    );
  }

  return {
    sessions: filteredSessions,
    allSessions,
    loading: state.loading,
    searchQuery: state.searchQuery,
    setSearchQuery,
    discoverSessions,
  };
}

